from __future__ import annotations

import base64
import gzip
from pathlib import Path

PAYLOAD = """"""

ROOT = Path(__file__).resolve().parents[1]
TARGET = ROOT / "intelligence_engine" / "intelligence_dashboard.py"
TARGET.write_bytes(gzip.decompress(base64.b64decode(PAYLOAD)))

# This installer is intentionally ephemeral.
for path in (
    Path(__file__),
    ROOT / ".github" / "workflows" / "_apply_dashboard_v2.yml",
):
    path.unlink(missing_ok=True)

print(f"wrote {TARGET}")
